import{_ as e,o as r,c as a,a4 as o}from"./chunks/framework.BybBnFXO.js";const p=JSON.parse('{"title":"Color Centers","description":"","frontmatter":{"title":"Color Centers","colorCause":"color-centers"},"headers":[],"relativePath":"color-causes/color-centers.md","filePath":"color-causes/color-centers.md","lastUpdated":1784176423000}'),n={name:"color-causes/color-centers.md"};function i(l,t,s,d,c,h){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="color-centers" tabindex="-1">Color Centers <a class="header-anchor" href="#color-centers" aria-label="Permalink to &quot;Color Centers&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Color centers are point defects in a crystal lattice that selectively absorb visible light. When an ion is missing (vacancy), extra (interstitial), or substituted by an impurity, nearby electrons or holes become trapped. Their energy levels often fall in the visible range, producing color. Color centers form naturally via radiation, or via artificial irradiation (which may fade with sunlight exposure — a key tell for treated material).</p><h2 id="mechanism" tabindex="-1">Mechanism <a class="header-anchor" href="#mechanism" aria-label="Permalink to &quot;Mechanism&quot;">​</a></h2><p>Common color-center types:</p><ul><li><strong>F-centers</strong> (anion vacancy trapping an electron): typical in fluorite and halite (rock salt)</li><li><strong>V-centers</strong> (cation vacancy trapping a hole): purple quartz (amethyst)</li><li><strong>Impurity centers</strong>: vacancy adjacent to a dopant ion, e.g. Fe⁴⁺ in amethyst Color centers can form rapidly under laboratory irradiation, but natural color centers accumulate over millions of years. Detection of irradiated gems often relies on characteristic short-wave UV luminescence signatures.</li></ul><h2 id="example-gemstones" tabindex="-1">Example Gemstones <a class="header-anchor" href="#example-gemstones" aria-label="Permalink to &quot;Example Gemstones&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Defect</th><th>Host</th><th>Color</th></tr></thead><tbody><tr><td>Amethyst / 紫晶</td><td>Fe⁴⁺ color center</td><td>SiO₂</td><td>violet</td></tr><tr><td>Smoky Quartz / 烟晶</td><td>Al impurity + e⁻</td><td>SiO₂</td><td>brown</td></tr><tr><td>Citrine / 黄水晶</td><td>Fe³⁺ color center</td><td>SiO₂</td><td>yellow</td></tr><tr><td>Fluorite / 萤石</td><td>F-center (vacancy)</td><td>CaF₂</td><td>purple / blue</td></tr><tr><td>Yellow Diamond / 黄钻</td><td>N + vacancy (H3)</td><td>C (diamond)</td><td>yellow</td></tr><tr><td>Pink Diamond / 粉钻</td><td>N + plastic deformation</td><td>C (diamond)</td><td>pink</td></tr></tbody></table><p><em>See the <a href="./intro.html">color cause overview</a>.</em></p>',9)])])}const u=e(n,[["render",i]]);export{p as __pageData,u as default};
